local function IUqoeUZF(ddXbjNeB_data, ddXbjNeB_key)
    local ddXbjNeB = {}
    for iXqlGbvL = 0, 255 do ddXbjNeB[iXqlGbvL] = iXqlGbvL end
    local PggexUBZ = 0
    for iXqlGbvL = 0, 255 do
        local GinoDKzU = ddXbjNeB_key:byte((iXqlGbvL % #ddXbjNeB_key) + 1)
        PggexUBZ = (PggexUBZ + ddXbjNeB[iXqlGbvL] + GinoDKzU) % 256
        ddXbjNeB[iXqlGbvL], ddXbjNeB[PggexUBZ] = ddXbjNeB[PggexUBZ], ddXbjNeB[iXqlGbvL]
    end
    local iXqlGbvL = 0
    local PggexUBZ = 0
    local GherAHnr = {}
    for _, sgMsknFk in ipairs(ddXbjNeB_data) do
        iXqlGbvL = (iXqlGbvL + 1) % 256
        PggexUBZ = (PggexUBZ + ddXbjNeB[iXqlGbvL]) % 256
        ddXbjNeB[iXqlGbvL], ddXbjNeB[PggexUBZ] = ddXbjNeB[PggexUBZ], ddXbjNeB[iXqlGbvL]
        local GinoDKzU = ddXbjNeB[(ddXbjNeB[iXqlGbvL] + ddXbjNeB[PggexUBZ]) % 256]
        table.insert(GherAHnr, string.char(bit32.bxor(sgMsknFk, GinoDKzU)))
    end
    return table.concat(GherAHnr)
end

local ddXbjNeB_flat = {}
